import{_ as i,o as a,c as l,al as r}from"./chunks/framework.DPRzuwkw.js";const s=JSON.parse('{"title":"数据包","description":"","frontmatter":{"next":{"text":"InWorld 配方系统","link":"/posts/docs/datapack/00_inworld_recipe"}},"headers":[],"relativePath":"posts/docs/datapack/index.md","filePath":"posts/docs/datapack/index.md","lastUpdated":1773840449000}'),_={name:"posts/docs/datapack/index.md"};function t(h,e,c,n,m,p){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="数据包" tabindex="-1">数据包 <a class="header-anchor" href="#数据包" aria-label="Permalink to “数据包”">​</a></h1><p>数据包支持是 AnvilCraft 的核心功能之一，允许通过 JSON 文件自定义各种配方和机制。以下文档将详细介绍每种配方类型的结构、字段和使用方法。</p><h2 id="配方" tabindex="-1">配方 <a class="header-anchor" href="#配方" aria-label="Permalink to “配方”">​</a></h2><p>这些配方类型构成了 AnvilCraft 的基础工艺系统：</p><ul><li><a href="./00_inworld_recipe.html">InWorld 配方</a> - 世界内配方系统，通过铁砧等机制触发</li><li><a href="./01_item_compress_recipe.html">物品压缩配方</a> - 将多个物品压缩成更高级的物品</li><li><a href="./02_block_compress_recipe.html">方块压缩配方</a> - 将多个方块压缩成更高级的方块</li><li><a href="./03_item_crush_recipe.html">物品粉碎配方</a> - 将物品粉碎成更小的物品</li><li><a href="./04_block_crush_recipe.html">方块粉碎配方</a> - 将方块粉碎成更小的方块或物品</li><li><a href="./05_stamping_recipe.html">冲压配方</a> - 在冲压平台上将物品转换为其他物品</li><li><a href="./06_bulging_recipe.html">膨发配方</a> - 使用炼药锅中的流体将物品膨发成其他物品</li><li><a href="./07_squeezing_recipe.html">挤压配方</a> - 使用炼药锅中的流体将方块挤压成其他方块</li><li><a href="./08_item_inject_recipe.html">物品注入配方</a> - 将流体注入物品中以创建新物品</li><li><a href="./09_cooking_recipe.html">烹饪配方</a> - 使用热源将物品烹饪成其他物品</li><li><a href="./10_super_heating_recipe.html">超级加热配方</a> - 使用高温流体将物品转换为其他物品</li><li><a href="./11_timewarp_recipe.html">时移配方</a> - 使用时间力量和流体将物品转换为其他物品</li><li><a href="./12_unpack_recipe.html">解包配方</a> - 将压缩物品解包为原始物品</li><li><a href="./13_block_smear_recipe.html">方块涂抹配方</a> - 使用上方方块涂抹下方方块</li><li><a href="./14_multiblock_recipe.html">多方块结构配方</a> - 定义复杂的多方块结构配方</li><li><a href="./15_mob_transform_recipe.html">生物转换配方</a> - 定义生物实体之间的转换规则</li><li><a href="./16_jewel_crafting_recipe.html">珠宝制作配方</a> - 制作各种珠宝和装饰性物品</li><li><a href="./17_mineral_fountain_recipe.html">矿物涌泉配方</a> - 定义矿物涌泉的方块转换规则</li><li><a href="./18_boiling_recipe.html">煮沸配方</a> - 在炼药锅和营火环境下进行煮沸处理</li><li><a href="./19_mesh_recipe.html">筛网配方</a> - 使用筛网/脚手架过滤并转化物品</li><li><a href="./20_mass_inject_recipe.html">质量注入配方</a> - 为物品注入质量值属性</li><li><a href="./21_stamping_unique_items_recipe.html">唯一物品冲压配方</a> - 仅接受不重复输入物品的冲压配方</li><li><a href="./22_mob_transform_with_item_recipe.html">带物品生物转换配方</a> - 通过手持物品概率触发生物特殊转换</li><li><a href="./23_multiblock_conversion_recipe.html">多方块转换配方</a> - 将匹配结构整体替换为另一套结构</li><li><a href="./24_mineral_fountain_chance_recipe.html">概率矿物涌泉配方</a> - 在指定维度按概率进行矿物涌泉转换</li><li><a href="./25_charger_charging_recipe.html">充放电配方</a> - 定义充电器/放电器的能量处理规则</li><li><a href="./26_multiple_to_one_smithing_recipe.html">多重合一锻造配方</a> - 多输入位锻造台配方（2/4/8 合一）</li><li><a href="./27_neutron_irradiation_recipe.html">中子辐照配方</a> - 在中子辐照器环境下进行处理</li><li><a href="./28_permutation_recipe.html">霜铸置换配方</a> - 霜铸系统中的置换型锻造配方</li><li><a href="./29_deformation_recipe.html">霜铸形变配方</a> - 霜铸系统中的形变型锻造配方</li><li><a href="./30_energy_weapon_make_recipe.html">能量武器制作配方</a> - 多材料组合生成能量武器</li><li><a href="./31_anvil_collision_recipe.html">铁砧碰撞工艺配方</a> - 通过铁砧撞击触发方块/掉落转换</li></ul><h2 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to “使用说明”">​</a></h2><p>要使用这些配方，您需要在您的数据包中创建相应的 JSON 文件，并将其放置在正确的目录结构中。每种配方类型都有其特定的结构和字段要求，请参考相应的文档了解详细信息。</p>',7)])])}const f=i(_,[["render",t]]);export{s as __pageData,f as default};
